    auto original = std::make_shared<int>(0);
    std::shared_ptr<int> copies[4];

    for (int i = 0; i < n; ++i) {
        copies[i] = original;
    }

    std::cout << "Count: " << original.use_count() << "\n";

    for (int i = 0; i < n; ++i) {
        copies[i].reset();
        std::cout << "Count: " << original.use_count() << "\n";
    }

    return 0;
}

