#include <iostream>
#include <memory>

std::shared_ptr<int> share_resource(std::shared_ptr<int> p) {
    std::cout << "Inside: " << p.use_count() << "\n";
    return p;
}

int main() {
    int v, n;
    std::cin >> v >> n;
    auto resource = std::make_shared<int>(v);
    for (int i = 0; i < n; ++i) {
        resource = share_resource(resource);
    }
    std::cout << "Final: " << *resource << "\n";
    return 0;
}
